{
  "@context": "https://schema.org",
  "@type": "FAQPage",
  "mainEntity": [{
    "@type": "Question",
    "name": "Combien de temps faut-il pour voir les résultats du SEO ?",
    "acceptedAnswer": {
      "@type": "Answer",
      "text": "Les premiers résultats (visibilité accrue, augmentation du trafic) peuvent apparaître en 3 à 6 mois. Des résultats significatifs en termes de ROI et de positionnement stable prennent généralement 6 à 12 mois, voire plus pour les marchés très compétitifs. Le SEO est un investissement à long terme."
    }
  }, {
    "@type": "Question",
    "name": "Quels sont les KPI que vous suivez pour mesurer le succès ?",
    "acceptedAnswer": {
      "@type": "Answer",
      "text": "Nous suivons des KPI tels que le trafic organique, les positions de mots-clés, le taux de conversion, le revenu généré par le SEO, le taux de rebond, le temps passé sur la page, et le taux de clics (CTR). Chaque client a un tableau de bord personnalisé."
    }
  }]
}
